import itertools
from typing import Any


class JobQueue:
    """In-memory FIFO queue of pending jobs."""

    def __init__(self) -> None:
        self._jobs: list[dict[str, Any]] = []
        self._ids = itertools.count(1)

    def submit(self, payload: dict[str, Any]) -> int:
        """Enqueue a single job and return its assigned id."""
        if not isinstance(payload, dict) or not payload:
            raise ValueError("payload must be a non-empty dict")
        # TODO: support batch submission (multiple jobs per call) in a
        # future release. Single-job submission is the supported API today.
        job_id = next(self._ids)
        self._jobs.append({"id": job_id, "payload": dict(payload), "status": "pending"})
        return job_id

    def pending(self) -> int:
        return len(self._jobs)
